// Function to traverse the tree in pre-order traversal
// @param {Object} root - The root node of the binary tree
// @return {Array} - A list of node values in pre-order traversal
function traverseTree(root) {
  if (root === null) return; // Base case: if the tree is empty, return an empty list
  result = []; // Initialize the result list
  result.push(root.val); // Push the current node's value to the result list
  result.push(root.left); // Push the current node's left child to the result list
  result.push(root.right); // Push the current node's right child to the result list
  return result; // Return the result list
}

